'use client'
import { useReducer } from "react";
import ProductCard from "./Card";
import Link from "next/link";

interface RatingAction {
    type: 'setRating' | 'removeRating';
    venueName: string;
    rating?: number;
}

export default function CardPanel() {
    
    const ratingReducer = (state: Map<string, number>, action: RatingAction) => {
        switch (action.type) {
            case 'setRating': {
                const newState = new Map(state);
                newState.set(action.venueName, action.rating ?? 0);
                return newState;
            }
            case 'removeRating': {
                const newState = new Map(state);
                newState.delete(action.venueName);
                return newState;
            }
            default:
                return state;
        }
    }

    const [ratingMap, dispatchRating] = useReducer(ratingReducer, new Map([
        ["The Bloom Pavilion", 0],
        ["Spark Space", 0],
        ["The Grand Table", 0]
    ]));

    const mockVenueRepo = [
        {vid:"001",name:"The Bloom Pavilion",image:"/img/bloom.jpg"},
        {vid:"002",name:"Spark Space",image:"/img/sparkspace.jpg"},
        {vid:"003",name:"The Grand Table",image:"/img/grandtable.jpg"}]

    return (
        <div className="w-full bg-[#faf9f6] py-10">
            
            {/* List รายการด้านล่าง*/}
            <div className="max-w-3xl mx-auto mt-20 p-8 border-t border-stone-200">
                <div className="flex justify-between items-end mb-6">
                    <h2 className="text-2xl font-serif text-stone-800">Review Summary</h2>
                    <span className="text-sm font-medium tracking-widest text-amber-700 uppercase">
                        Active Reviews: {ratingMap.size}
                    </span>
                </div>

                <div className="space-y-3">
                    {
                        Array.from(ratingMap).map(([name, value]) => (
                            <div 
                                key={name}
                                data-testid={name}
                                onClick={(e) => {
                                    e.preventDefault();
                                    dispatchRating({ type: 'removeRating', venueName: name });
                                }}
                                className="group flex justify-between items-center p-4 rounded-xl 
                                           bg-white border border-transparent hover:border-amber-200 
                                           hover:shadow-md transition-all duration-300 cursor-pointer"
                            >
                                <span className="text-stone-700 font-medium group-hover:text-amber-800 transition-colors">
                                    {name}
                                </span>
                                <div className="flex items-center gap-3">
                                    <span className="text-amber-600 font-bold">{value} Stars</span>
                                    <span className="text-stone-300 group-hover:text-red-400 text-xs uppercase tracking-tighter transition-colors">
                                        Click to remove
                                    </span>
                                </div>
                            </div>
                        ))
                    }
                </div>

                {ratingMap.size === 0 && (
                    <div className="text-center py-10 text-stone-400 italic">
                        No venues selected for review.
                    </div>
                )}
            </div>
        </div>
    );
}